 46→class CachingSessionStore
 47→    extends WrappedStateStore<SessionStore<Bytes, byte[]>, byte[], byte[]>
 48→    implements SessionStore<Bytes, byte[]>, CachedStateStore<byte[], byte[]> {
 49→
 50→    private static final Logger LOG = LoggerFactory.getLogger(CachingSessionStore.class);
 51→
 52→    private final SessionKeySchema keySchema;
 53→    private final SegmentedCacheFunction cacheFunction;
 54→    private static final String INVALID_RANGE_WARN_MSG = "Returning empty iterator for fetch with invalid key range: from > to. " +
 55→        "This may be due to range arguments set in the wrong order, " +
 56→        "or serdes that don't preserve ordering when lexicographically comparing the serialized bytes. " +
 57→        "Note that the built-in numerical serdes do not follow this for negative numbers";
 58→
 59→    private String cacheName;
 60→    private InternalProcessorContext<?, ?> internalContext;
 61→    private CacheFlushListener<byte[], byte[]> flushListener;
 62→    private boolean sendOldValues;
 63→
 64→    private long maxObservedTimestamp; // Refers to the window end time (determines segmentId)
 65→
 66→    CachingSessionStore(final SessionStore<Bytes, byte[]> bytesStore,
 67→                        final long segmentInterval) {
 68→        super(bytesStore);
 69→        this.keySchema = new SessionKeySchema();
 70→        this.cacheFunction = new SegmentedCacheFunction(keySchema, segmentInterval);
 71→        this.maxObservedTimestamp = RecordQueue.UNKNOWN;
 72→    }
 73→
 74→    @Override
 75→    public void init(final StateStoreContext stateStoreContext, final StateStore root) {
 76→        internalContext = asInternalProcessorContext(stateStoreContext);
 77→        cacheName = internalContext.taskId() + "-" + name();
 78→        internalContext.registerCacheFlushListener(cacheName, entries -> {
 79→            for (final ThreadCache.DirtyEntry entry : entries) {
 80→                putAndMaybeForward(entry, internalContext);
 81→            }
 82→        });
 83→        super.init(stateStoreContext, root);
 84→    }
 85→
 86→    private void putAndMaybeForward(final ThreadCache.DirtyEntry entry, final InternalProcessorContext<?, ?> context) {
 87→        final Bytes binaryKey = cacheFunction.key(entry.key());
 88→        final Windowed<Bytes> bytesKey = SessionKeySchema.from(binaryKey);
 89→        if (flushListener != null) {
 90→            final byte[] newValueBytes = entry.newValue();
 91→            final byte[] oldValueBytes = newValueBytes == null || sendOldValues ?
 92→                wrapped().fetchSession(bytesKey.key(), bytesKey.window().start(), bytesKey.window().end()) : null;
 93→
 94→            // this is an optimization: if this key did not exist in underlying store and also not in the cache,
 95→            // we can skip flushing to downstream as well as writing to underlying store
 96→            if (newValueBytes != null || oldValueBytes != null) {
 97→                // we need to get the old values if needed, and then put to store, and then flush
 98→
 99→                final ProcessorRecordContext current = context.recordContext();
100→                try {
101→                    context.setRecordContext(entry.entry().context());
102→                    wrapped().put(bytesKey, entry.newValue());
103→                    flushListener.apply(
104→                        new Record<>(
105→                            binaryKey.get(),
106→                            new Change<>(newValueBytes, sendOldValues ? oldValueBytes : null),
107→                            entry.entry().context().timestamp(),
108→                            entry.entry().context().headers()));
109→                } finally {
110→                    context.setRecordContext(current);
111→                }
112→            }
113→        } else {
114→            final ProcessorRecordContext current = context.recordContext();
115→            try {
116→                context.setRecordContext(entry.entry().context());
117→                wrapped().put(bytesKey, entry.newValue());
118→            } finally {
119→                context.setRecordContext(current);
120→            }
121→        }
122→    }
123→
124→    @Override
125→    public boolean setFlushListener(final CacheFlushListener<byte[], byte[]> flushListener,
126→                                    final boolean sendOldValues) {
127→        this.flushListener = flushListener;
128→        this.sendOldValues = sendOldValues;
129→
130→        return true;
131→    }
