133→    @Override
134→    public void put(final Windowed<Bytes> key, final byte[] value) {
135→        validateStoreOpen();
136→        final Bytes binaryKey = SessionKeySchema.toBinary(key);
137→        final LRUCacheEntry entry =
138→            new LRUCacheEntry(
139→                value,
140→                internalContext.recordContext().headers(),
141→                true,
142→                internalContext.recordContext().offset(),
143→                internalContext.recordContext().timestamp(),
144→                internalContext.recordContext().partition(),
145→                internalContext.recordContext().topic(),
146→                internalContext.recordContext().sourceRawKey(),
147→                internalContext.recordContext().sourceRawValue()
148→            );
149→        internalContext.cache().put(cacheName, cacheFunction.cacheKey(binaryKey), entry);
150→
151→        maxObservedTimestamp = Math.max(keySchema.segmentTimestamp(binaryKey), maxObservedTimestamp);
152→    }
153→
154→    @Override
155→    public void remove(final Windowed<Bytes> sessionKey) {
156→        validateStoreOpen();
157→        put(sessionKey, null);
158→    }
