160→    @Override
161→    public KeyValueIterator<Windowed<Bytes>, byte[]> findSessions(final Bytes key,
162→                                                                  final long earliestSessionEndTime,
163→                                                                  final long latestSessionStartTime) {
164→        validateStoreOpen();
165→
166→        final PeekingKeyValueIterator<Bytes, LRUCacheEntry> cacheIterator = wrapped().persistent() ?
167→            new CacheIteratorWrapper(key, earliestSessionEndTime, latestSessionStartTime, true) :
168→            internalContext.cache().range(cacheName,
169→                        cacheFunction.cacheKey(keySchema.lowerRangeFixedSize(key, earliestSessionEndTime)),
170→                        cacheFunction.cacheKey(keySchema.upperRangeFixedSize(key, latestSessionStartTime))
171→            );
172→
173→        final KeyValueIterator<Windowed<Bytes>, byte[]> storeIterator = wrapped().findSessions(key,
174→                                                                                               earliestSessionEndTime,
175→                                                                                               latestSessionStartTime);
176→        final HasNextCondition hasNextCondition = keySchema.hasNextCondition(key,
177→                                                                             key,
178→                                                                             earliestSessionEndTime,
179→                                                                             latestSessionStartTime,
180→                                                                             true);
181→        final PeekingKeyValueIterator<Bytes, LRUCacheEntry> filteredCacheIterator =
182→            new FilteredCacheIterator(cacheIterator, hasNextCondition, cacheFunction);
183→        return new MergedSortedCacheSessionStoreIterator(filteredCacheIterator, storeIterator, cacheFunction, true);
184→    }
