186→    @Override
187→    public KeyValueIterator<Windowed<Bytes>, byte[]> backwardFindSessions(final Bytes key,
188→                                                                          final long earliestSessionEndTime,
189→                                                                          final long latestSessionStartTime) {
190→        validateStoreOpen();
191→
192→        final PeekingKeyValueIterator<Bytes, LRUCacheEntry> cacheIterator = wrapped().persistent() ?
193→            new CacheIteratorWrapper(key, earliestSessionEndTime, latestSessionStartTime, false) :
194→            internalContext.cache().reverseRange(
195→                cacheName,
196→                cacheFunction.cacheKey(keySchema.lowerRangeFixedSize(key, earliestSessionEndTime)),
197→                cacheFunction.cacheKey(keySchema.upperRangeFixedSize(key, latestSessionStartTime)
198→                )
199→            );
200→
201→        final KeyValueIterator<Windowed<Bytes>, byte[]> storeIterator = wrapped().backwardFindSessions(
202→            key,
203→            earliestSessionEndTime,
204→            latestSessionStartTime
205→        );
206→        final HasNextCondition hasNextCondition = keySchema.hasNextCondition(
207→            key,
208→            key,
209→            earliestSessionEndTime,
210→            latestSessionStartTime,
211→            false
212→        );
213→        final PeekingKeyValueIterator<Bytes, LRUCacheEntry> filteredCacheIterator =
214→            new FilteredCacheIterator(cacheIterator, hasNextCondition, cacheFunction);
215→        return new MergedSortedCacheSessionStoreIterator(filteredCacheIterator, storeIterator, cacheFunction, false);
216→    }
