218→    @Override
219→    public KeyValueIterator<Windowed<Bytes>, byte[]> findSessions(final Bytes keyFrom,
220→                                                                  final Bytes keyTo,
221→                                                                  final long earliestSessionEndTime,
222→                                                                  final long latestSessionStartTime) {
223→        if (keyFrom != null && keyTo != null && keyFrom.compareTo(keyTo) > 0) {
224→            LOG.warn(INVALID_RANGE_WARN_MSG);
225→            return KeyValueIterators.emptyIterator();
226→        }
227→
228→        validateStoreOpen();
229→
230→        final Bytes cacheKeyFrom = keyFrom == null ? null : cacheFunction.cacheKey(keySchema.lowerRange(keyFrom, earliestSessionEndTime));
231→        final Bytes cacheKeyTo = keyTo == null ? null : cacheFunction.cacheKey(keySchema.upperRange(keyTo, latestSessionStartTime));
232→        final ThreadCache.MemoryLRUCacheBytesIterator cacheIterator = internalContext.cache().range(cacheName, cacheKeyFrom, cacheKeyTo);
233→
234→        final KeyValueIterator<Windowed<Bytes>, byte[]> storeIterator = wrapped().findSessions(
235→            keyFrom, keyTo, earliestSessionEndTime, latestSessionStartTime
236→        );
237→        final HasNextCondition hasNextCondition = keySchema.hasNextCondition(keyFrom,
238→                                                                             keyTo,
239→                                                                             earliestSessionEndTime,
240→                                                                             latestSessionStartTime,
241→                                                                     true);
242→        final PeekingKeyValueIterator<Bytes, LRUCacheEntry> filteredCacheIterator =
243→            new FilteredCacheIterator(cacheIterator, hasNextCondition, cacheFunction);
244→        return new MergedSortedCacheSessionStoreIterator(filteredCacheIterator, storeIterator, cacheFunction, true);
245→    }
