247→    @Override
248→    public KeyValueIterator<Windowed<Bytes>, byte[]> backwardFindSessions(final Bytes keyFrom,
249→                                                                          final Bytes keyTo,
250→                                                                          final long earliestSessionEndTime,
251→                                                                          final long latestSessionStartTime) {
252→        if (keyFrom != null && keyTo != null && keyFrom.compareTo(keyTo) > 0) {
253→            LOG.warn(INVALID_RANGE_WARN_MSG);
254→            return KeyValueIterators.emptyIterator();
255→        }
256→
257→        validateStoreOpen();
258→
259→        final Bytes cacheKeyFrom = keyFrom == null ? null : cacheFunction.cacheKey(keySchema.lowerRange(keyFrom, earliestSessionEndTime));
260→        final Bytes cacheKeyTo = keyTo == null ? null : cacheFunction.cacheKey(keySchema.upperRange(keyTo, latestSessionStartTime));
261→        final ThreadCache.MemoryLRUCacheBytesIterator cacheIterator = internalContext.cache().reverseRange(cacheName, cacheKeyFrom, cacheKeyTo);
262→
263→        final KeyValueIterator<Windowed<Bytes>, byte[]> storeIterator =
264→            wrapped().backwardFindSessions(keyFrom, keyTo, earliestSessionEndTime, latestSessionStartTime);
265→        final HasNextCondition hasNextCondition = keySchema.hasNextCondition(
266→            keyFrom,
267→            keyTo,
268→            earliestSessionEndTime,
269→            latestSessionStartTime,
270→            false
271→        );
272→        final PeekingKeyValueIterator<Bytes, LRUCacheEntry> filteredCacheIterator =
273→            new FilteredCacheIterator(cacheIterator, hasNextCondition, cacheFunction);
274→        return new MergedSortedCacheSessionStoreIterator(filteredCacheIterator, storeIterator, cacheFunction, false);
275→    }
