277→    @Override
278→    public byte[] fetchSession(final Bytes key, final long earliestSessionEndTime, final long latestSessionStartTime) {
279→        Objects.requireNonNull(key, "key cannot be null");
280→        validateStoreOpen();
281→        if (internalContext.cache() == null) {
282→            return wrapped().fetchSession(key, earliestSessionEndTime, latestSessionStartTime);
283→        } else {
284→            final Bytes bytesKey = SessionKeySchema.toBinary(key, earliestSessionEndTime,
285→                latestSessionStartTime);
286→            final Bytes cacheKey = cacheFunction.cacheKey(bytesKey);
287→            final LRUCacheEntry entry = internalContext.cache().get(cacheName, cacheKey);
288→            if (entry == null) {
289→                return wrapped().fetchSession(key, earliestSessionEndTime, latestSessionStartTime);
290→            } else {
291→                return entry.value();
292→            }
293→        }
294→    }
295→
296→    @Override
297→    public KeyValueIterator<Windowed<Bytes>, byte[]> fetch(final Bytes key) {
298→        Objects.requireNonNull(key, "key cannot be null");
299→        return findSessions(key, 0, Long.MAX_VALUE);
300→    }
301→
302→    @Override
303→    public KeyValueIterator<Windowed<Bytes>, byte[]> backwardFetch(final Bytes key) {
304→        Objects.requireNonNull(key, "key cannot be null");
