308→    @Override
309→    public KeyValueIterator<Windowed<Bytes>, byte[]> fetch(final Bytes keyFrom,
310→                                                           final Bytes keyTo) {
311→        return findSessions(keyFrom, keyTo, 0, Long.MAX_VALUE);
312→    }
313→
314→    @Override
315→    public KeyValueIterator<Windowed<Bytes>, byte[]> backwardFetch(final Bytes keyFrom,
316→                                                                   final Bytes keyTo) {
317→        return backwardFindSessions(keyFrom, keyTo, 0, Long.MAX_VALUE);
318→    }
