333→        internalContext.cache().clear(cacheName);
334→    }
335→
336→    public void close() {
337→        final LinkedList<RuntimeException> suppressed = executeAll(
338→            () -> internalContext.cache().flush(cacheName),
339→            () -> internalContext.cache().close(cacheName),
340→            wrapped()::close
341→        );
342→        if (!suppressed.isEmpty()) {
343→            throwSuppressed("Caught an exception while closing caching session store for store " + name(),
344→                            suppressed);
345→        }
346→    }
