348→    private class CacheIteratorWrapper implements PeekingKeyValueIterator<Bytes, LRUCacheEntry> {
349→
350→        private final long segmentInterval;
351→
352→        private final Bytes keyFrom;
353→        private final Bytes keyTo;
354→        private final long latestSessionStartTime;
355→        private final boolean forward;
356→
357→        private long lastSegmentId;
358→
359→        private long currentSegmentId;
360→        private Bytes cacheKeyFrom;
361→        private Bytes cacheKeyTo;
362→
363→        private ThreadCache.MemoryLRUCacheBytesIterator current;
364→
365→        private CacheIteratorWrapper(final Bytes key,
366→                                     final long earliestSessionEndTime,
367→                                     final long latestSessionStartTime,
368→                                     final boolean forward) {
369→            this(key, key, earliestSessionEndTime, latestSessionStartTime, forward);
370→        }
371→
372→        private CacheIteratorWrapper(final Bytes keyFrom,
373→                                     final Bytes keyTo,
374→                                     final long earliestSessionEndTime,
375→                                     final long latestSessionStartTime,
376→                                     final boolean forward) {
377→            this.keyFrom = keyFrom;
378→            this.keyTo = keyTo;
379→            this.latestSessionStartTime = latestSessionStartTime;
380→            this.segmentInterval = cacheFunction.getSegmentInterval();
381→            this.forward = forward;
382→
383→
384→            if (forward) {
385→                this.currentSegmentId = cacheFunction.segmentId(earliestSessionEndTime);
386→                this.lastSegmentId = cacheFunction.segmentId(maxObservedTimestamp);
387→
388→                setCacheKeyRange(earliestSessionEndTime, currentSegmentLastTime());
389→                this.current = internalContext.cache().range(cacheName, cacheKeyFrom, cacheKeyTo);
390→            } else {
391→                this.lastSegmentId = cacheFunction.segmentId(earliestSessionEndTime);
392→                this.currentSegmentId = cacheFunction.segmentId(maxObservedTimestamp);
393→
394→                setCacheKeyRange(currentSegmentBeginTime(), Math.min(latestSessionStartTime, maxObservedTimestamp));
395→                this.current = internalContext.cache().reverseRange(cacheName, cacheKeyFrom, cacheKeyTo);
396→            }
397→        }
398→
399→        @Override
400→        public boolean hasNext() {
401→            if (current == null) {
402→                return false;
403→            }
404→
405→            if (current.hasNext()) {
406→                return true;
407→            }
408→
409→            while (!current.hasNext()) {
410→                getNextSegmentIterator();
411→                if (current == null) {
412→                    return false;
413→                }
414→            }
415→            return true;
416→        }
417→
418→        @Override
419→        public Bytes peekNextKey() {
420→            if (!hasNext()) {
421→                throw new NoSuchElementException();
422→            }
423→            return current.peekNextKey();
424→        }
425→
426→        @Override
427→        public KeyValue<Bytes, LRUCacheEntry> peekNext() {
428→            if (!hasNext()) {
429→                throw new NoSuchElementException();
430→            }
431→            return current.peekNext();
432→        }
433→
434→        @Override
435→        public KeyValue<Bytes, LRUCacheEntry> next() {
436→            if (!hasNext()) {
437→                throw new NoSuchElementException();
438→            }
439→            return current.next();
440→        }
441→
442→        @Override
443→        public void close() {
444→            current.close();
445→        }
446→
447→        private long currentSegmentBeginTime() {
448→            return currentSegmentId * segmentInterval;
449→        }
450→
451→        private long currentSegmentLastTime() {
452→            return currentSegmentBeginTime() + segmentInterval - 1;
453→        }
454→
455→        private void getNextSegmentIterator() {
456→            if (forward) {
457→                ++currentSegmentId;
458→                lastSegmentId = cacheFunction.segmentId(maxObservedTimestamp);
459→
460→                if (currentSegmentId > lastSegmentId) {
461→                    current = null;
462→                    return;
463→                }
464→
465→                setCacheKeyRange(currentSegmentBeginTime(), currentSegmentLastTime());
466→
467→                current.close();
468→
469→                current = internalContext.cache().range(cacheName, cacheKeyFrom, cacheKeyTo);
470→            } else {
471→                --currentSegmentId;
472→
473→                if (currentSegmentId < lastSegmentId) {
474→                    current = null;
475→                    return;
476→                }
477→
478→                setCacheKeyRange(currentSegmentBeginTime(), currentSegmentLastTime());
479→
480→                current.close();
481→
482→                current = internalContext.cache().reverseRange(cacheName, cacheKeyFrom, cacheKeyTo);
483→            }
484→
485→        }
486→
487→        private void setCacheKeyRange(final long lowerRangeEndTime, final long upperRangeEndTime) {
488→            if (cacheFunction.segmentId(lowerRangeEndTime) != cacheFunction.segmentId(upperRangeEndTime)) {
489→                throw new IllegalStateException("Error iterating over segments: segment interval has changed");
490→            }
491→
492→            if (keyFrom.equals(keyTo)) {
493→                cacheKeyFrom = cacheFunction.cacheKey(segmentLowerRangeFixedSize(keyFrom, lowerRangeEndTime));
494→                cacheKeyTo = cacheFunction.cacheKey(segmentUpperRangeFixedSize(keyTo, upperRangeEndTime));
495→            } else {
496→                cacheKeyFrom = cacheFunction.cacheKey(keySchema.lowerRange(keyFrom, lowerRangeEndTime), currentSegmentId);
497→                cacheKeyTo = cacheFunction.cacheKey(keySchema.upperRange(keyTo, latestSessionStartTime), currentSegmentId);
498→            }
499→        }
500→
501→        private Bytes segmentLowerRangeFixedSize(final Bytes key, final long segmentBeginTime) {
502→            final Windowed<Bytes> sessionKey = new Windowed<>(key, new SessionWindow(0, Math.max(0, segmentBeginTime)));
503→            return SessionKeySchema.toBinary(sessionKey);
504→        }
505→
506→        private Bytes segmentUpperRangeFixedSize(final Bytes key, final long segmentEndTime) {
507→            final Windowed<Bytes> sessionKey = new Windowed<>(key, new SessionWindow(Math.min(latestSessionStartTime, segmentEndTime), segmentEndTime));
508→            return SessionKeySchema.toBinary(sessionKey);
509→        }
510→    }
511→}
