 49→class CachingWindowStore
 50→    extends WrappedStateStore<WindowStore<Bytes, byte[]>, byte[], byte[]>
 51→    implements WindowStore<Bytes, byte[]>, CachedStateStore<byte[], byte[]> {
 52→
 53→    private static final Logger LOG = LoggerFactory.getLogger(CachingWindowStore.class);
 54→
 55→    private final long windowSize;
 56→    private final SegmentedCacheFunction cacheFunction;
 57→    private final SegmentedBytesStore.KeySchema keySchema = new WindowKeySchema();
 58→
 59→    private String cacheName;
 60→    private boolean sendOldValues;
 61→    private InternalProcessorContext<?, ?> internalContext;
 62→    private StateSerdes<Bytes, byte[]> bytesSerdes;
 63→    private CacheFlushListener<byte[], byte[]> flushListener;
 64→
 65→    private final AtomicLong maxObservedTimestamp;
 66→
 67→    CachingWindowStore(final WindowStore<Bytes, byte[]> underlying,
 68→                       final long windowSize,
 69→                       final long segmentInterval) {
 70→        super(underlying);
 71→        this.windowSize = windowSize;
 72→        this.cacheFunction = new SegmentedCacheFunction(keySchema, segmentInterval);
 73→        this.maxObservedTimestamp = new AtomicLong(RecordQueue.UNKNOWN);
 74→    }
 75→
 76→    @Override
 77→    public void init(final StateStoreContext stateStoreContext, final StateStore root) {
 78→        final String changelogTopic = ProcessorContextUtils.changelogFor(stateStoreContext, name(), Boolean.TRUE);
 79→        internalContext = asInternalProcessorContext(stateStoreContext);
 80→        bytesSerdes = new StateSerdes<>(
 81→            changelogTopic,
 82→            Serdes.Bytes(),
 83→            Serdes.ByteArray());
 84→        cacheName = internalContext.taskId() + "-" + name();
 85→
 86→        internalContext.registerCacheFlushListener(cacheName, entries -> {
 87→            for (final ThreadCache.DirtyEntry entry : entries) {
 88→                putAndMaybeForward(entry, internalContext);
 89→            }
 90→        });
 91→
 92→        super.init(stateStoreContext, root);
 93→    }
 94→
 95→    private void putAndMaybeForward(final ThreadCache.DirtyEntry entry,
 96→                                    final InternalProcessorContext<?, ?> context) {
 97→        final byte[] binaryWindowKey = cacheFunction.key(entry.key()).get();
