441→    private class CacheIteratorWrapper implements PeekingKeyValueIterator<Bytes, LRUCacheEntry> {
442→
443→        private final long segmentInterval;
444→        private final Bytes keyFrom;
445→        private final Bytes keyTo;
446→        private final long timeTo;
447→        private final boolean forward;
448→
449→        private long lastSegmentId;
450→        private long currentSegmentId;
451→        private Bytes cacheKeyFrom;
452→        private Bytes cacheKeyTo;
453→
454→        private ThreadCache.MemoryLRUCacheBytesIterator current;
455→
456→        private CacheIteratorWrapper(final Bytes key,
457→                                     final long timeFrom,
458→                                     final long timeTo,
459→                                     final boolean forward) {
460→            this(key, key, timeFrom, timeTo, forward);
461→        }
462→
463→        private CacheIteratorWrapper(final Bytes keyFrom,
464→                                     final Bytes keyTo,
465→                                     final long timeFrom,
466→                                     final long timeTo,
467→                                     final boolean forward) {
468→            this.keyFrom = keyFrom;
469→            this.keyTo = keyTo;
470→            this.timeTo = timeTo;
471→            this.forward = forward;
472→
473→            this.segmentInterval = cacheFunction.getSegmentInterval();
474→
475→            if (forward) {
476→                this.lastSegmentId = cacheFunction.segmentId(Math.min(timeTo, maxObservedTimestamp.get()));
477→                this.currentSegmentId = cacheFunction.segmentId(timeFrom);
478→
479→                setCacheKeyRange(timeFrom, currentSegmentLastTime());
480→                this.current = internalContext.cache().range(cacheName, cacheKeyFrom, cacheKeyTo);
481→            } else {
482→                this.currentSegmentId = cacheFunction.segmentId(Math.min(timeTo, maxObservedTimestamp.get()));
483→                this.lastSegmentId = cacheFunction.segmentId(timeFrom);
484→
485→                setCacheKeyRange(currentSegmentBeginTime(), Math.min(timeTo, maxObservedTimestamp.get()));
486→                this.current = internalContext.cache().reverseRange(cacheName, cacheKeyFrom, cacheKeyTo);
487→            }
488→        }
489→
490→        @Override
491→        public boolean hasNext() {
492→            if (current == null) {
493→                return false;
494→            }
495→
496→            if (current.hasNext()) {
497→                return true;
498→            }
499→
500→            while (!current.hasNext()) {
501→                getNextSegmentIterator();
502→                if (current == null) {
503→                    return false;
504→                }
505→            }
506→            return true;
507→        }
508→
509→        @Override
510→        public Bytes peekNextKey() {
511→            if (!hasNext()) {
512→                throw new NoSuchElementException();
513→            }
514→            return current.peekNextKey();
515→        }
516→
517→        @Override
518→        public KeyValue<Bytes, LRUCacheEntry> peekNext() {
519→            if (!hasNext()) {
520→                throw new NoSuchElementException();
521→            }
522→            return current.peekNext();
523→        }
524→
525→        @Override
526→        public KeyValue<Bytes, LRUCacheEntry> next() {
527→            if (!hasNext()) {
528→                throw new NoSuchElementException();
529→            }
530→            return current.next();
531→        }
532→
533→        @Override
534→        public void close() {
535→            current.close();
536→        }
537→
538→        private long currentSegmentBeginTime() {
539→            return currentSegmentId * segmentInterval;
540→        }
541→
542→        private long currentSegmentLastTime() {
543→            return Math.min(timeTo, currentSegmentBeginTime() + segmentInterval - 1);
544→        }
545→
546→        private void getNextSegmentIterator() {
547→            if (forward) {
548→                ++currentSegmentId;
549→                // updating as maxObservedTimestamp can change while iterating
550→                lastSegmentId = cacheFunction.segmentId(Math.min(timeTo, maxObservedTimestamp.get()));
551→
552→                if (currentSegmentId > lastSegmentId) {
553→                    current = null;
554→                    return;
555→                }
556→
557→                setCacheKeyRange(currentSegmentBeginTime(), currentSegmentLastTime());
558→
559→                current.close();
560→
561→                current = internalContext.cache().range(cacheName, cacheKeyFrom, cacheKeyTo);
562→            } else {
563→                --currentSegmentId;
564→
565→                // last segment id is stable when iterating backward, therefore no need to update
566→                if (currentSegmentId < lastSegmentId) {
567→                    current = null;
568→                    return;
569→                }
570→
571→                setCacheKeyRange(currentSegmentBeginTime(), currentSegmentLastTime());
572→
573→                current.close();
574→
575→                current = internalContext.cache().reverseRange(cacheName, cacheKeyFrom, cacheKeyTo);
576→            }
577→        }
578→
579→        private void setCacheKeyRange(final long lowerRangeEndTime, final long upperRangeEndTime) {
580→            if (cacheFunction.segmentId(lowerRangeEndTime) != cacheFunction.segmentId(upperRangeEndTime)) {
581→                throw new IllegalStateException("Error iterating over segments: segment interval has changed");
582→            }
583→
584→            if (keyFrom != null && keyFrom.equals(keyTo)) {
585→                cacheKeyFrom = cacheFunction.cacheKey(segmentLowerRangeFixedSize(keyFrom, lowerRangeEndTime));
586→                cacheKeyTo = cacheFunction.cacheKey(segmentUpperRangeFixedSize(keyTo, upperRangeEndTime));
587→            } else {
588→                cacheKeyFrom = keyFrom == null ? null :
589→                    cacheFunction.cacheKey(keySchema.lowerRange(keyFrom, lowerRangeEndTime), currentSegmentId);
590→                cacheKeyTo = keyTo == null ? null :
591→                    cacheFunction.cacheKey(keySchema.upperRange(keyTo, timeTo), currentSegmentId);
592→            }
593→        }
594→
595→        private Bytes segmentLowerRangeFixedSize(final Bytes key, final long segmentBeginTime) {
596→            return WindowKeySchema.toStoreKeyBinary(key, Math.max(0, segmentBeginTime), 0);
597→        }
598→
599→        private Bytes segmentUpperRangeFixedSize(final Bytes key, final long segmentEndTime) {
600→            return WindowKeySchema.toStoreKeyBinary(key, segmentEndTime, Integer.MAX_VALUE);
601→        }
602→    }
603→}
