 68→    private final SegmentedCacheFunction baseKeyCacheFunction;
 69→    private final SegmentedCacheFunction indexKeyCacheFunction;
 70→    private final TimeFirstWindowKeySchema baseKeySchema = new TimeFirstWindowKeySchema();
 71→    private final KeyFirstWindowKeySchema indexKeySchema = new KeyFirstWindowKeySchema();
 72→
 73→    private String cacheName;
 74→    private boolean hasIndex;
 75→    private boolean sendOldValues;
 76→    private InternalProcessorContext<?, ?> internalContext;
