 82→    TimeOrderedCachingWindowStore(final WindowStore<Bytes, byte[]> underlying,
 83→                                  final long windowSize,
 84→                                  final long segmentInterval) {
 85→        super(underlying);
 86→        this.windowSize = windowSize;
 87→        this.baseKeyCacheFunction = new SegmentedCacheFunction(baseKeySchema, segmentInterval);
 88→        this.indexKeyCacheFunction = new SegmentedCacheFunction(indexKeySchema, segmentInterval);
 89→        this.maxObservedTimestamp = new AtomicLong(RecordQueue.UNKNOWN);
 90→        enforceWrappedStore(underlying);
 91→    }
