 93→    private void enforceWrappedStore(final WindowStore<Bytes, byte[]> underlying) {
 94→        final RocksDBTimeOrderedWindowStore timeOrderedWindowStore = getWrappedStore(underlying);
 95→        if (timeOrderedWindowStore == null) {
 96→            throw new IllegalArgumentException("TimeOrderedCachingWindowStore only supports RocksDBTimeOrderedWindowStore backed store");
 97→        }
 98→
 99→        hasIndex = timeOrderedWindowStore.hasIndex();
100→    }
