102→    @SuppressWarnings("unchecked")
103→    private RocksDBTimeOrderedWindowStore getWrappedStore(final StateStore wrapped) {
104→        if (wrapped instanceof RocksDBTimeOrderedWindowStore) {
105→            return (RocksDBTimeOrderedWindowStore) wrapped;
106→        }
107→        if (wrapped instanceof WrappedStateStore) {
108→            return getWrappedStore(((WrappedStateStore<?, Bytes, byte[]>) wrapped).wrapped());
