242→    private Bytes indexKeyToBaseKey(final Bytes indexKey) {
243→        final byte[] key = KeyFirstWindowKeySchema.extractStoreKeyBytes(indexKey.get());
244→        final long timestamp = KeyFirstWindowKeySchema.extractStoreTimestamp(indexKey.get());
245→        final int seqnum = KeyFirstWindowKeySchema.extractStoreSequence(indexKey.get());
246→        return TimeFirstWindowKeySchema.toStoreKeyBinary(key, timestamp, seqnum);
247→    }
