298→    @Override
299→    public byte[] fetch(final Bytes key,
300→                        final long timestamp) {
301→        validateStoreOpen();
302→        if (internalContext.cache() == null) {
303→            return wrapped().fetch(key, timestamp);
304→        }
305→
306→        final Bytes baseBytesKey = TimeFirstWindowKeySchema.toStoreKeyBinary(key, timestamp, 0);
307→        final Bytes cacheKey = baseKeyCacheFunction.cacheKey(baseBytesKey);
308→
309→        final LRUCacheEntry entry = internalContext.cache().get(cacheName, cacheKey);
310→        if (entry == null) {
311→            return wrapped().fetch(key, timestamp);
312→        } else {
313→            return entry.value();
314→        }
315→    }
