349→    private WindowStoreIterator<byte[]> fetchInternal(final WindowStoreIterator<byte[]> underlyingIterator,
350→                                                      final Bytes key,
351→                                                      final long timeFrom,
352→                                                      final long timeTo,
353→                                                      final boolean forward) {
354→        final PeekingKeyValueIterator<Bytes, LRUCacheEntry> cacheIterator = new CacheIteratorWrapper(
355→            key, timeFrom, timeTo, forward, hasIndex);
356→        final KeySchema keySchema = hasIndex ? indexKeySchema : baseKeySchema;
357→        final SegmentedCacheFunction cacheFunction = hasIndex ? indexKeyCacheFunction : baseKeyCacheFunction;
358→        final HasNextCondition hasNextCondition = keySchema.hasNextCondition(key, key, timeFrom, timeTo, forward);
359→
360→        final PeekingKeyValueIterator<Bytes, LRUCacheEntry> filteredCacheIterator =
361→            new FilteredCacheIterator(cacheIterator, hasNextCondition, cacheFunction);
362→
363→        final Function<byte[], Long> tsExtractor = hasIndex ? KeyFirstWindowKeySchema::extractStoreTimestamp
364→            : TimeFirstWindowKeySchema::extractStoreTimestamp;
365→        return new MergedSortedCacheWindowStoreIterator(filteredCacheIterator, underlyingIterator, forward, tsExtractor);
366→    }
