538→    private class CacheIteratorWrapper implements PeekingKeyValueIterator<Bytes, LRUCacheEntry> {
539→
540→        private final long segmentInterval;
541→        private final Bytes keyFrom;
542→        private final Bytes keyTo;
543→        private final long timeTo;
544→        private final boolean forward;
545→        private final boolean useIndex; // If we are iterating from index
546→
547→        private long lastSegmentId;
548→        private long currentSegmentId;
549→        private Bytes cacheKeyFrom;
550→        private Bytes cacheKeyTo;
551→        private LRUCacheEntry cachedBaseValue;
552→        private final SegmentedCacheFunction cacheFunction;
553→
554→        private ThreadCache.MemoryLRUCacheBytesIterator current;
555→
556→        private CacheIteratorWrapper(final Bytes key,
557→                                     final long timeFrom,
558→                                     final long timeTo,
559→                                     final boolean forward,
560→                                     final boolean index) {
561→            this(key, key, timeFrom, timeTo, forward, index);
562→        }
563→
564→        private CacheIteratorWrapper(final Bytes keyFrom,
565→                                     final Bytes keyTo,
566→                                     final long timeFrom,
567→                                     final long timeTo,
568→                                     final boolean forward,
569→                                     final boolean index) {
570→            this.keyFrom = keyFrom;
571→            this.keyTo = keyTo;
572→            this.timeTo = timeTo;
573→            this.forward = forward;
574→            this.useIndex = index;
575→
576→            cacheFunction = index ? indexKeyCacheFunction : baseKeyCacheFunction;
577→
578→            this.segmentInterval = cacheFunction.getSegmentInterval();
579→
580→            if (forward) {
581→                this.lastSegmentId = cacheFunction.segmentId(Math.min(timeTo, maxObservedTimestamp.get()));
582→                this.currentSegmentId = cacheFunction.segmentId(timeFrom);
583→
584→                setCacheKeyRange(timeFrom, currentSegmentLastTime());
585→                this.current = internalContext.cache().range(cacheName, cacheKeyFrom, cacheKeyTo);
586→            } else {
587→                this.currentSegmentId = cacheFunction.segmentId(Math.min(timeTo, maxObservedTimestamp.get()));
588→                this.lastSegmentId = cacheFunction.segmentId(timeFrom);
589→
590→                setCacheKeyRange(currentSegmentBeginTime(), Math.min(timeTo, maxObservedTimestamp.get()));
591→                this.current = internalContext.cache().reverseRange(cacheName, cacheKeyFrom, cacheKeyTo);
592→            }
593→        }
594→
595→        @Override
596→        public boolean hasNext() {
597→            if (current == null) {
598→                return false;
599→            }
600→
601→            if (useIndex) {
602→                do {
603→                    // If iterating from index, need to make sure base key/value exist in cache
604→                    while (current.hasNext()) {
605→                        final Bytes cacheIndexKey = current.peekNextKey();
606→                        final Bytes indexKey = indexKeyCacheFunction.key(cacheIndexKey);
607→                        final Bytes baseKey = indexKeyToBaseKey(indexKey);
608→                        final Bytes cachedBaseKey = baseKeyCacheFunction.cacheKey(baseKey);
609→                        cachedBaseValue = internalContext.cache().get(cacheName, cachedBaseKey);
610→                        if (cachedBaseValue != null) {
611→                            return true;
612→                        }
613→                        current.next();
614→                    }
615→                    getNextSegmentIterator();
616→                } while (current != null);
617→                return false;
618→            }
619→
620→            if (current.hasNext()) {
621→                return true;
622→            }
623→
624→            while (!current.hasNext()) {
625→                getNextSegmentIterator();
626→                if (current == null) {
627→                    return false;
628→                }
629→            }
630→            return true;
631→        }
632→
633→        @Override
634→        public Bytes peekNextKey() {
635→            if (!hasNext()) {
636→                throw new NoSuchElementException();
637→            }
638→            return current.peekNextKey();
639→        }
640→
641→        @Override
642→        public KeyValue<Bytes, LRUCacheEntry> peekNext() {
643→            if (!hasNext()) {
644→                throw new NoSuchElementException();
645→            }
646→            if (useIndex) {
647→                final KeyValue<Bytes, LRUCacheEntry> kv = current.peekNext();
648→                return KeyValue.pair(kv.key, cachedBaseValue);
649→            }
650→            return current.peekNext();
651→        }
652→
653→        @Override
654→        public KeyValue<Bytes, LRUCacheEntry> next() {
655→            if (!hasNext()) {
656→                throw new NoSuchElementException();
657→            }
658→            if (useIndex) {
659→                final KeyValue<Bytes, LRUCacheEntry> kv = current.next();
660→                return KeyValue.pair(kv.key, cachedBaseValue);
661→            }
662→            return current.next();
663→        }
664→
665→        @Override
666→        public void close() {
667→            current.close();
668→        }
669→
670→        private long currentSegmentBeginTime() {
671→            return currentSegmentId * segmentInterval;
672→        }
673→
674→        private long currentSegmentLastTime() {
675→            return Math.min(timeTo, currentSegmentBeginTime() + segmentInterval - 1);
676→        }
677→
678→        private void getNextSegmentIterator() {
679→            if (forward) {
680→                ++currentSegmentId;
681→                // updating as maxObservedTimestamp can change while iterating
682→                lastSegmentId = cacheFunction.segmentId(Math.min(timeTo, maxObservedTimestamp.get()));
683→
684→                if (currentSegmentId > lastSegmentId) {
685→                    current = null;
686→                    return;
687→                }
688→
689→                setCacheKeyRange(currentSegmentBeginTime(), currentSegmentLastTime());
690→
691→                current.close();
692→
693→                current = internalContext.cache().range(cacheName, cacheKeyFrom, cacheKeyTo);
694→            } else {
695→                --currentSegmentId;
696→
697→                // last segment id is stable when iterating backward, therefore no need to update
698→                if (currentSegmentId < lastSegmentId) {
699→                    current = null;
700→                    return;
701→                }
702→
703→                setCacheKeyRange(currentSegmentBeginTime(), currentSegmentLastTime());
704→
705→                current.close();
706→
707→                current = internalContext.cache().reverseRange(cacheName, cacheKeyFrom, cacheKeyTo);
708→            }
709→        }
710→
711→        private void setCacheKeyRange(final long lowerRangeEndTime, final long upperRangeEndTime) {
712→            if (cacheFunction.segmentId(lowerRangeEndTime) != cacheFunction.segmentId(upperRangeEndTime)) {
713→                throw new IllegalStateException("Error iterating over segments: segment interval has changed");
714→            }
715→
716→            final KeySchema schema = useIndex ? indexKeySchema : baseKeySchema;
717→
718→            if (keyFrom != null && keyFrom.equals(keyTo)) {
719→                cacheKeyFrom = cacheFunction.cacheKey(schema.lowerRangeFixedSize(keyFrom, lowerRangeEndTime), currentSegmentId);
720→                cacheKeyTo = cacheFunction.cacheKey(schema.upperRangeFixedSize(keyTo, upperRangeEndTime), currentSegmentId);
721→            } else {
722→                cacheKeyFrom = cacheFunction.cacheKey(schema.lowerRange(keyFrom, lowerRangeEndTime), currentSegmentId);
723→                cacheKeyTo = cacheFunction.cacheKey(schema.upperRange(keyTo, timeTo), currentSegmentId);
724→            }
725→        }
726→    }
727→}
